      out.write("                                            'L': ['Lai Châu','Lâm Đồng','Lạng Sơn','Lào Cai','Long An'],\r\n");
      out.write("                                            'N': ['Nam Định','Nghệ An','Ninh Bình','Ninh Thuận'],\r\n");
      out.write("                                            'P': ['Phú Thọ','Phú Yên'],\r\n");
