      out.write("                                            'S': ['Sóc Trăng','Sơn La'],\r\n");
      out.write("                                            'T': ['Tây Ninh','Thái Bình','Thái Nguyên','Thanh Hóa','Thừa Thiên Huế','Tiền Giang','TP. Hồ Chí Minh','Trà Vinh','Tuyên Quang'],\r\n");
      out.write("                                            'V': ['Vĩnh Long','Vĩnh Phúc'],\r\n");
