      out.write("                                            // Sync sidebar checked locations into modal\r\n");
      out.write("                                            modalSelectedLocations.clear();\r\n");
      out.write("                                            document.querySelectorAll('#filterForm input[name=\"location\"]:checked').forEach(function(cb) {\r\n");
