      out.write("                                        }\r\n");
      out.write("\r\n");
      out.write("                                        function renderModalProvinces(filter) {\r\n");
      out.write("                                            var html = '';\r\n");
      out.write("                                            var letters = Object.keys(allProvinces);\r\n");
      out.write("                                            filter = filter.toLowerCase();\r\n");
      out.write("                                            letters.forEach(function(letter) {\r\n");
      out.write("                                                var provinces = allProvinces[letter].filter(function(p) {\r\n");
      out.write("                                                    return filter === '' || p.toLowerCase().indexOf(filter) >= 0;\r\n");
      out.write("                                                });\r\n");
      out.write("                                                if (provinces.length === 0) return;\r\n");
      out.write("                                                html += '<div id=\"loc-letter-' + letter + '\" style=\"margin-bottom:5px;\">';\r\n");
      out.write("                                                html += '<div style=\"font-weight:600;font-size:14px;color:rgba(0,0,0,.65);padding:8px 0;border-bottom:1px solid #f0f0f0;\">' + letter + '</div>';\r\n");
      out.write("                                                html += '<div style=\"display:grid;grid-template-columns:repeat(4,1fr);gap:0;\">';\r\n");
      out.write("                                                provinces.forEach(function(p) {\r\n");
      out.write("                                                    var checked = modalSelectedLocations.has(p) ? 'checked' : '';\r\n");
      out.write("                                                    html += '<label style=\"display:flex;align-items:center;padding:10px 5px;font-size:13px;color:rgba(0,0,0,.8);cursor:pointer;\">';\r\n");
      out.write("                                                    html += '<input type=\"checkbox\" class=\"modal-loc-cb\" value=\"' + p + '\" ' + checked + ' style=\"margin-right:8px;width:14px;height:14px;\"> ' + p;\r\n");
      out.write("                                                    html += '</label>';\r\n");
      out.write("                                                });\r\n");
      out.write("                                                html += '</div></div>';\r\n");
      out.write("                                            });\r\n");
      out.write("                                            if (html === '') {\r\n");
      out.write("                                                html = '<div style=\"text-align:center;padding:40px;color:#999;\">Không tìm thấy tỉnh/thành phố nào</div>';\r\n");
      out.write("                                            }\r\n");
      out.write("                                            document.getElementById('locModalBody').innerHTML = html;\r\n");
      out.write("                                            // Re-bind checkboxes\r\n");
      out.write("                                            document.querySelectorAll('.modal-loc-cb').forEach(function(cb) {\r\n");
      out.write("                                                cb.addEventListener('change', function() {\r\n");
      out.write("                                                    if (this.checked) modalSelectedLocations.add(this.value);\r\n");
      out.write("                                                    else modalSelectedLocations.delete(this.value);\r\n");
      out.write("                                                });\r\n");
      out.write("                                            });\r\n");
      out.write("                                        }\r\n");
      out.write("\r\n");
