      out.write("                                            if (el) el.scrollIntoView({ behavior: 'smooth', block: 'start' });\r\n");
      out.write("                                        }\r\n");
      out.write("\r\n");
      out.write("                                        function resetModalLocations() {\r\n");
      out.write("                                            modalSelectedLocations.clear();\r\n");
      out.write("                                            document.querySelectorAll('.modal-loc-cb').forEach(function(cb) {\r\n");
      out.write("                                                cb.checked = false;\r\n");
      out.write("                                            });\r\n");
      out.write("                                        }\r\n");
      out.write("\r\n");
      out.write("                                        function confirmModalLocations() {\r\n");
      out.write("                                            // Uncheck all sidebar location checkboxes first\r\n");
      out.write("                                            document.querySelectorAll('#filterForm input[name=\"location\"]').forEach(function(cb) {\r\n");
      out.write("                                                cb.checked = false;\r\n");
      out.write("                                            });\r\n");
      out.write("                                            // Check the ones selected in modal (if they exist in sidebar)\r\n");
      out.write("                                            modalSelectedLocations.forEach(function(loc) {\r\n");
      out.write("                                                var existing = document.querySelector('#filterForm input[name=\"location\"][value=\"' + loc + '\"]');\r\n");
      out.write("                                                if (existing) {\r\n");
      out.write("                                                    existing.checked = true;\r\n");
      out.write("                                                } else {\r\n");
      out.write("                                                    // Add hidden input for locations not in sidebar\r\n");
      out.write("                                                    var hidden = document.createElement('input');\r\n");
      out.write("                                                    hidden.type = 'hidden';\r\n");
      out.write("                                                    hidden.name = 'location';\r\n");
      out.write("                                                    hidden.value = loc;\r\n");
      out.write("                                                    hidden.className = 'modal-added-loc';\r\n");
      out.write("                                                    document.getElementById('filterForm').appendChild(hidden);\r\n");
      out.write("                                                }\r\n");
      out.write("                                            });\r\n");
      out.write("                                            // Remove old hidden inputs that are no longer selected\r\n");
      out.write("                                            document.querySelectorAll('.modal-added-loc').forEach(function(h) {\r\n");
      out.write("                                                if (!modalSelectedLocations.has(h.value)) h.remove();\r\n");
      out.write("                                            });\r\n");
      out.write("                                            closeLocationModal();\r\n");
      out.write("                                            // Submit form to apply location filter\r\n");
      out.write("                                            document.getElementById('filterForm').submit();\r\n");
      out.write("                                        }\r\n");
      out.write("                                    </script>\r\n");
